    shape.lineTo(Math.cos(a1) * rA, Math.sin(a1) * rA);
    shape.lineTo(Math.cos(a2) * rB, Math.sin(a2) * rB);
    shape.lineTo(Math.cos(a3) * rB, Math.sin(a3) * rB);
