import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls';

const tags = [
  '⚙️ Mechanical', '⚡ Electrical', '📡 IoT',
  '📟 Embedded', '🤖 Robotics', '💻 Software',
  '🔩 Hardware', '🧊 3D Design',
];

/* ─── Gear geometry ─────────────────────────── */
function buildGear(teeth, innerR, outerR, toothW = 0.45, depth = 0.26) {
  const shape = new THREE.Shape();
  const total = teeth * 2;
  for (let i = 0; i < total; i++) {
    const a0 = (i / total) * Math.PI * 2;
    const a1 = ((i + toothW) / total) * Math.PI * 2;
    const a2 = ((i + toothW + 0.05) / total) * Math.PI * 2;
    const a3 = ((i + 1) / total) * Math.PI * 2;
    const rA = i % 2 === 0 ? outerR : innerR;
    const rB = i % 2 === 0 ? innerR : outerR;
    const fn = i === 0 ? 'moveTo' : 'lineTo';
    shape[fn](Math.cos(a0) * rA, Math.sin(a0) * rA);
    shape.lineTo(Math.cos(a1) * rA, Math.sin(a1) * rA);
    shape.lineTo(Math.cos(a2) * rB, Math.sin(a2) * rB);
    shape.lineTo(Math.cos(a3) * rB, Math.sin(a3) * rB);
  }
  shape.closePath();
  const hole = new THREE.Path();
  hole.absarc(0, 0, innerR * 0.42, 0, Math.PI * 2, true);
  shape.holes.push(hole);
  return new THREE.ExtrudeGeometry(shape, {
    depth, bevelEnabled: true,
    bevelThickness: 0.022, bevelSize: 0.016, bevelSegments: 3,
  });
}

function buildHub(r, depth) {
  return new THREE.CylinderGeometry(r, r, depth + 0.07, 32);
}

/* ─── Scene 1: Gear Mechanism ───────────────── */
function initGearScene(mount) {
  const W = mount.clientWidth;
  const H = mount.clientHeight;

  const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
  renderer.setSize(W, H);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.setClearColor(0x000000, 0);
  mount.appendChild(renderer.domElement);

  const scene  = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(48, W / H, 0.1, 100);
  camera.position.set(0, 0, 4.8); // Perbesar dan dekatkan

  const controls = new OrbitControls(camera, renderer.domElement);
  controls.enableDamping   = true;
  controls.dampingFactor   = 0.07;
  controls.enableZoom      = true;
  controls.zoomSpeed       = 0.5;
  controls.minDistance     = 3.5;
  controls.maxDistance     = 10;
  controls.autoRotate      = true;
  controls.autoRotateSpeed = 0.7;
  controls.addEventListener('start', () => { controls.autoRotate = false; });

  // Lighting
  scene.add(new THREE.AmbientLight(0xffffff, 0.2));
  const d1 = new THREE.DirectionalLight(0x00f5ff, 2.2);
  d1.position.set(5, 7, 6); scene.add(d1);
  const d2 = new THREE.DirectionalLight(0xbf00ff, 1.4);
  d2.position.set(-5, -4, -3); scene.add(d2);
  const d3 = new THREE.DirectionalLight(0x00f5ff, 0.5);
  d3.position.set(0, -5, 2); scene.add(d3);

  const matCyan = new THREE.MeshStandardMaterial({
    color: 0x003344, emissive: 0x00b8cc, emissiveIntensity: 0.42,
    metalness: 0.92, roughness: 0.2,
  });
  const matPurple = new THREE.MeshStandardMaterial({
    color: 0x1a0033, emissive: 0x9900dd, emissiveIntensity: 0.48,
    metalness: 0.92, roughness: 0.18,
  });
  const matAccent = new THREE.MeshStandardMaterial({
    color: 0x002233, emissive: 0x004466, emissiveIntensity: 0.55,
    metalness: 0.95, roughness: 0.12,
  });

  const group = new THREE.Group();
  group.position.set(0.2, 0.45, 0); // geser ke kanan atas supaya full terlihat
  scene.add(group);

  // Big gear
  const bigGeo = buildGear(16, 0.84, 1.24, 0.42, 0.28);
  bigGeo.center();
  const bigGear = new THREE.Mesh(bigGeo, matCyan);
  bigGear.position.set(-1.05, 0.1, 0);
  group.add(bigGear);
  const bigHub = new THREE.Mesh(buildHub(0.33, 0.28), matAccent);
  bigHub.rotation.x = Math.PI / 2;
  bigHub.position.copy(bigGear.position);
  group.add(bigHub);

  // Medium gear
  const medR = 0.80;
  const medGeo = buildGear(10, 0.54, medR, 0.42, 0.25);
  medGeo.center();
  const medGear = new THREE.Mesh(medGeo, matPurple);
  medGear.position.set(bigGear.position.x + 1.24 + medR - 0.065, 0.1, 0);
  group.add(medGear);
  const medHub = new THREE.Mesh(buildHub(0.22, 0.25), matAccent);
  medHub.rotation.x = Math.PI / 2;
  medHub.position.copy(medGear.position);
  group.add(medHub);

  // Small gear (top of medium)
  const smR = 0.52;
  const smGeo = buildGear(6, 0.35, smR, 0.42, 0.22);
  smGeo.center();
  const smGear = new THREE.Mesh(smGeo, matCyan);
  smGear.position.set(medGear.position.x, medGear.position.y + medR + smR - 0.058, 0.06);
  group.add(smGear);
  const smHub = new THREE.Mesh(buildHub(0.15, 0.22), matAccent);
  smHub.rotation.x = Math.PI / 2;
  smHub.position.copy(smGear.position);
  group.add(smHub);

  // Tiny gear (bottom of big)
  const tyR = 0.62;
  const tyGeo = buildGear(8, 0.42, tyR, 0.42, 0.20);
  tyGeo.center();
  const tinyGear = new THREE.Mesh(tyGeo, matPurple);
  tinyGear.position.set(bigGear.position.x - 0.08, bigGear.position.y - 1.24 - tyR + 0.056, -0.05);
  group.add(tinyGear);
  const tyHub = new THREE.Mesh(buildHub(0.17, 0.20), matAccent);
  tyHub.rotation.x = Math.PI / 2;
  tyHub.position.copy(tinyGear.position);
  group.add(tyHub);

  // Particles
  const pPos = new Float32Array(80 * 3);
  for (let i = 0; i < 80; i++) {
    pPos[i*3]   = (Math.random()-0.5)*6;
    pPos[i*3+1] = (Math.random()-0.5)*6;
    pPos[i*3+2] = (Math.random()-0.5)*3;
  }
  const pGeo = new THREE.BufferGeometry();
  pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
  const particles = new THREE.Points(pGeo, new THREE.PointsMaterial({
    color: 0x00f5ff, size: 0.024, transparent: true, opacity: 0.4,
  }));
  scene.add(particles);

  const bigSpeed  =  0.30;
  const medSpeed  = -(16/10) * bigSpeed;
  const smSpeed   = -(10/ 6) * medSpeed;
  const tinySpeed = -(16/ 8) * bigSpeed;

  let frameId;
  const clock = new THREE.Clock();
  const animate = () => {
    frameId = requestAnimationFrame(animate);
    const dt = clock.getDelta();
    const t  = clock.elapsedTime;

    bigGear.rotation.z  += bigSpeed  * dt;
    medGear.rotation.z  += medSpeed  * dt;
    smGear.rotation.z   += smSpeed   * dt;
    tinyGear.rotation.z += tinySpeed * dt;

    group.rotation.x = Math.sin(t * 0.18) * 0.10;
    group.rotation.y = Math.sin(t * 0.13) * 0.07;
    particles.rotation.y += 0.00012;

    controls.update();
    renderer.render(scene, camera);
  };
  animate();

  const onResize = () => {
    const nw = mount.clientWidth, nh = mount.clientHeight;
    camera.aspect = nw / nh;
    camera.updateProjectionMatrix();
    renderer.setSize(nw, nh);
  };
  window.addEventListener('resize', onResize);

  return () => {
    cancelAnimationFrame(frameId);
    controls.dispose();
    window.removeEventListener('resize', onResize);
    renderer.dispose();
    if (mount.contains(renderer.domElement)) mount.removeChild(renderer.domElement);
  };
}

/* ─── Scene 2: PCB Board ────────────────────── */
function initPCBScene(mount) {
  const W = mount.clientWidth;
  const H = mount.clientHeight;

  const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
  renderer.setSize(W, H);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.setClearColor(0x000000, 0);
  mount.appendChild(renderer.domElement);

  const scene  = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(46, W / H, 0.1, 100);
  camera.position.set(0, 1.8, 6.5);
  camera.lookAt(0, 0, 0);

  const controls = new OrbitControls(camera, renderer.domElement);
  controls.enableDamping   = true;
  controls.dampingFactor   = 0.07;
  controls.enableZoom      = true;
  controls.zoomSpeed       = 0.5;
  controls.minDistance     = 3;
  controls.maxDistance     = 12;
  controls.autoRotate      = true;
  controls.autoRotateSpeed = 0.4;
  controls.addEventListener('start', () => { controls.autoRotate = false; });

  scene.add(new THREE.AmbientLight(0xffffff, 0.18));
  const d1 = new THREE.DirectionalLight(0x00f5ff, 1.8);
  d1.position.set(4, 6, 5); scene.add(d1);
  const d2 = new THREE.DirectionalLight(0xbf00ff, 1.2);
  d2.position.set(-4, -3, -3); scene.add(d2);
  const d3 = new THREE.DirectionalLight(0x00ff88, 0.6);
  d3.position.set(0, -4, 4); scene.add(d3);

  const group = new THREE.Group();
  scene.add(group);

  // Board
  const boardMat = new THREE.MeshStandardMaterial({
    color: 0x001a0d, emissive: 0x002810, emissiveIntensity: 0.7,
    metalness: 0.3, roughness: 0.75,
  });
  const boardGeo = new THREE.BoxGeometry(5.8, 3.4, 0.13);
  const board = new THREE.Mesh(boardGeo, boardMat);
  group.add(board);

  // Board edge
  group.add(new THREE.LineSegments(
    new THREE.EdgesGeometry(boardGeo),
    new THREE.LineBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.55 })
  ));

  // IC chips
  const chipMat = new THREE.MeshStandardMaterial({
    color: 0x080808, emissive: 0x001122, emissiveIntensity: 0.5,
    metalness: 0.85, roughness: 0.25,
  });
  const goldMat = new THREE.MeshStandardMaterial({
    color: 0xccaa00, emissive: 0x886600, emissiveIntensity: 0.9, metalness: 1,
  });
  const chips = [
    { x: -1.7, y:  0.6, w: 1.0, h: 0.95, pins: 5 },
    { x:  0.2, y:  0.55, w: 1.2, h: 0.72, pins: 6 },
    { x:  1.7, y: -0.4, w: 0.75, h: 0.75, pins: 4 },
    { x: -0.5, y: -0.65, w: 0.65, h: 0.52, pins: 4 },
    { x:  1.85, y:  0.65, w: 0.52, h: 0.42, pins: 3 },
    { x: -1.9, y: -0.55, w: 0.52, h: 0.62, pins: 3 },
  ];
  chips.forEach(c => {
    const cGeo = new THREE.BoxGeometry(c.w, c.h, 0.09);
    const chip = new THREE.Mesh(cGeo, chipMat);
    chip.position.set(c.x, c.y, 0.115);
    group.add(chip);
    const edges = new THREE.LineSegments(
      new THREE.EdgesGeometry(cGeo),
      new THREE.LineBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.75 })
    );
    edges.position.copy(chip.position);
    group.add(edges);
    // Pins left side
    for (let p = 0; p < c.pins; p++) {
      const pin = new THREE.Mesh(new THREE.BoxGeometry(0.07, 0.045, 0.03), goldMat);
      pin.position.set(
        c.x - c.w / 2 - 0.05,
        c.y - (c.h / 2) + (p + 0.5) * (c.h / c.pins),
        0.09
      );
      group.add(pin);
    }
  });

  // Trace lines
  const trCyan   = new THREE.LineBasicMaterial({ color: 0x00f5ff, transparent: true, opacity: 0.38 });
  const trPurple = new THREE.LineBasicMaterial({ color: 0xbf00ff, transparent: true, opacity: 0.30 });
  const trGreen  = new THREE.LineBasicMaterial({ color: 0x00ff88, transparent: true, opacity: 0.28 });
  const traces = [
    { pts: [[-2.6,0.6],[-1.7,0.6]], m: trCyan },
    { pts: [[-1.2,0.6],[0.2,0.6]], m: trCyan },
    { pts: [[0.8,0.6],[1.7,0.6]], m: trPurple },
    { pts: [[0.2,0.19],[0.2,-0.29]], m: trGreen },
    { pts: [[-0.5,-0.39],[1.7,-0.39]], m: trCyan },
    { pts: [[-1.7,0.13],[-1.7,-0.55]], m: trPurple },
    { pts: [[-1.7,-0.55],[-0.5,-0.55]], m: trPurple },
    { pts: [[1.7,-0.03],[1.7,-0.39]], m: trGreen },
    { pts: [[2.1,0.65],[2.6,0.65]], m: trCyan },
    { pts: [[-2.1,-0.55],[-2.6,-0.55]], m: trPurple },
    { pts: [[0.5,-0.65],[0.5,-1.3]], m: trGreen },
    { pts: [[-0.8,0.6],[-0.8,1.25]], m: trCyan },
    { pts: [[-0.8,1.25],[0.5,1.25]], m: trPurple },
    { pts: [[0.5,1.25],[0.5,-0.65]], m: trGreen },
  ];
  traces.forEach(({ pts, m }) => {
    const points = pts.map(([x, y]) => new THREE.Vector3(x, y, 0.145));
    group.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(points), m));
  });

  // Capacitors
  const capMat = new THREE.MeshStandardMaterial({
    color: 0x002244, emissive: 0x0055cc, emissiveIntensity: 0.7, metalness: 0.7, roughness: 0.3,
  });
  [[-0.8, 1.05], [0.5, -1.05], [2.15, 0.05], [-2.15, 0.22]].forEach(([x, y]) => {
    const cap = new THREE.Mesh(new THREE.CylinderGeometry(0.11, 0.11, 0.25, 14), capMat);
    cap.rotation.x = Math.PI / 2;
    cap.position.set(x, y, 0.185);
    group.add(cap);
  });

  // Mounting holes (corner rings)
  const ringMat = new THREE.MeshStandardMaterial({
    color: 0x998800, emissive: 0x554400, metalness: 1,
  });
  [[-2.5, 1.45], [2.5, 1.45], [-2.5, -1.45], [2.5, -1.45]].forEach(([x, y]) => {
    const ring = new THREE.Mesh(new THREE.TorusGeometry(0.13, 0.028, 8, 24), ringMat);
    ring.position.set(x, y, 0.14);
    group.add(ring);
  });

  // Particles
  const pPos = new Float32Array(60 * 3);
  for (let i = 0; i < 60; i++) {
    pPos[i*3]   = (Math.random()-0.5)*7;
    pPos[i*3+1] = (Math.random()-0.5)*5;
    pPos[i*3+2] = (Math.random()-0.5)*3;
  }
  const pGeo = new THREE.BufferGeometry();
  pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
  scene.add(new THREE.Points(pGeo, new THREE.PointsMaterial({
    color: 0x00f5ff, size: 0.02, transparent: true, opacity: 0.35,
  })));

  let frameId;
  const clock = new THREE.Clock();
  const animate = () => {
    frameId = requestAnimationFrame(animate);
    const t = clock.elapsedTime;
    clock.getDelta();

    group.position.y = Math.sin(t * 0.5) * 0.07;
    group.rotation.z = Math.sin(t * 0.3) * 0.012;

    controls.update();
    renderer.render(scene, camera);
  };
  animate();

  const onResize = () => {
    const nw = mount.clientWidth, nh = mount.clientHeight;
    camera.aspect = nw / nh;
    camera.updateProjectionMatrix();
    renderer.setSize(nw, nh);
  };
  window.addEventListener('resize', onResize);

  return () => {
    cancelAnimationFrame(frameId);
    controls.dispose();
    window.removeEventListener('resize', onResize);
    renderer.dispose();
    if (mount.contains(renderer.domElement)) mount.removeChild(renderer.domElement);
  };
}

